def event_data(item):return{"id":item.id,"title":item.title,"event_type_id":item.event_type_id,"event_type":item.event_type.name,"color":item.event_type.color,"date":item.event_date.isoformat(),"start_time":item.start_time.strftime("%H:%M")if item.start_time else None,"end_time":item.end_time.strftime("%H:%M")if item.end_time else None,"is_all_day":item.is_all_day,"location":item.location,"audience":item.department.name if item.department else"Everyone","description":item.description,"status":item.status}
def notice_data(item):return{"id":item.id,"title":item.title,"content":item.content,"priority":item.priority,"date":item.published_at.date().isoformat()if item.published_at else None,"status":item.status,"audience":item.department.name if item.department else"All Employees"}
def type_data(item):return{"id":item.id,"name":item.name,"color":item.color}
